import { useState } from 'react';
import { Menu, X } from 'lucide-react';
import { useAuth } from '../lib/AuthContext';
import AuthModal from './AuthModal';
import ProfileMenu from './ProfileMenu';

interface Props {
  current: string;
  navigate: (to: string) => void;
}

const LINKS = [
  { href: '/', label: 'Current Week' },
  { href: '/archive', label: 'Archive' },
  { href: '/community', label: 'Community Sets' },
  { href: '/skill-tree', label: 'Skill Tree' },
  { href: '/forum', label: 'Forum' },
  { href: '/sandbox', label: 'Sandbox' },
];

export default function Nav({ current, navigate }: Props) {
  const { user, signOut, isHost } = useAuth();
  const [open, setOpen] = useState(false);
  const [authOpen, setAuthOpen] = useState(false);
  const [authMode, setAuthMode] = useState<'signin' | 'signup'>('signin');

  const go = (to: string) => {
    navigate(to);
    setOpen(false);
  };

  const openAuth = (mode: 'signin' | 'signup') => {
    setAuthMode(mode);
    setAuthOpen(true);
    setOpen(false);
  };

  const isActive = (href: string) =>
    href === '/' ? current === '/' : current.startsWith(href);

  return (
    <>
      <header className="sticky top-0 z-40 border-b border-ink-700/70 bg-ink-900/85 backdrop-blur-md">
        <div className="mx-auto flex h-16 max-w-6xl items-center justify-between px-4 sm:px-6">
          <button
            onClick={() => go('/home')}
            className="group flex items-center gap-2.5 focus-ring rounded-md"
            aria-label="ZeroSet home"
          >
            <span className="relative flex h-8 w-8 items-center justify-center">
              <span className="absolute inset-0 rounded-full border border-accent-400/60" />
              <span className="absolute inset-1.5 rounded-full border border-accent-400/30" />
              <span className="h-1.5 w-1.5 rounded-full bg-accent-400 shadow-glow" />
            </span>
            <span className="font-serif text-lg font-semibold tracking-tight text-ink-50">
              ZeroSet
            </span>
            <span className="hidden font-mono text-[10px] uppercase tracking-[0.2em] text-ink-400 sm:inline">
              / weekly math
            </span>
          </button>

          <nav className="hidden items-center gap-1 md:flex">
            {LINKS.map((l) => (
              <button
                key={l.href}
                onClick={() => go(l.href)}
                className={`focus-ring rounded-md px-3 py-1.5 text-sm font-medium transition ${
                  isActive(l.href)
                    ? 'text-accent-200'
                    : 'text-ink-300 hover:text-ink-100'
                }`}
              >
                {l.label}
              </button>
            ))}
            {isHost && (
              <button
                onClick={() => go('/host')}
                className={`focus-ring rounded-md px-3 py-1.5 text-sm font-medium transition ${
                  current === '/host' ? 'text-accent-200' : 'text-ink-300 hover:text-ink-100'
                }`}
              >
                Host
              </button>
            )}
          </nav>

          <ProfileMenu navigate={go} onSignIn={() => openAuth('signin')} onSignUp={() => openAuth('signup')} />

          <button
            onClick={() => setOpen((v) => !v)}
            className="focus-ring rounded-md p-2 text-ink-200 md:hidden"
            aria-label="Menu"
          >
            {open ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </button>
        </div>

        {open && (
          <div className="border-t border-ink-700 bg-ink-900 px-4 py-3 md:hidden">
            <nav className="flex flex-col gap-1">
              {LINKS.map((l) => (
                <button
                  key={l.href}
                  onClick={() => go(l.href)}
                  className={`focus-ring rounded-md px-3 py-2 text-left text-sm font-medium ${
                    isActive(l.href) ? 'text-accent-200' : 'text-ink-200'
                  }`}
                >
                  {l.label}
                </button>
              ))}
              {isHost && (
                <button
                  onClick={() => go('/host')}
                  className={`focus-ring rounded-md px-3 py-2 text-left text-sm font-medium ${
                    current === '/host' ? 'text-accent-200' : 'text-ink-200'
                  }`}
                >
                  Host dashboard
                </button>
              )}
            </nav>
            <div className="mt-3 border-t border-ink-700 pt-3">
              {user ? (
                <div className="flex flex-col gap-1">
                  <button
                    onClick={() => { go('/me'); }}
                    className="focus-ring flex w-full items-center gap-2 rounded-md px-3 py-2 text-left text-sm text-ink-200 hover:text-accent-200"
                  >
                    Account stats
                  </button>
                  <button
                    onClick={() => { go('/me/settings'); }}
                    className="focus-ring flex w-full items-center gap-2 rounded-md px-3 py-2 text-left text-sm text-ink-200 hover:text-accent-200"
                  >
                    Settings
                  </button>
                  {isHost && (
                    <button
                      onClick={() => { go('/host'); }}
                      className="focus-ring flex w-full items-center gap-2 rounded-md px-3 py-2 text-left text-sm text-ink-200 hover:text-accent-200"
                    >
                      Host dashboard
                    </button>
                  )}
                  <button
                    onClick={() => {
                      signOut();
                      setOpen(false);
                    }}
                    className="focus-ring flex w-full items-center gap-2 rounded-md px-3 py-2 text-left text-sm text-red-300"
                  >
                    Sign out
                  </button>
                </div>
              ) : (
                <div className="flex gap-2">
                  <button
                    onClick={() => openAuth('signin')}
                    className="focus-ring flex-1 rounded-md border border-ink-700 px-3 py-2 text-sm text-ink-200"
                  >
                    Sign in
                  </button>
                  <button
                    onClick={() => openAuth('signup')}
                    className="focus-ring flex-1 rounded-md border border-accent-400 bg-accent-400/15 px-3 py-2 text-sm font-semibold text-accent-200"
                  >
                    Join
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </header>

      <AuthModal open={authOpen} onClose={() => setAuthOpen(false)} mode={authMode} />
    </>
  );
}

src/components/ProblemCard.tsx:
import { useEffect, useState } from 'react';
import { Lock, ChevronDown, ChevronUp, Lightbulb, BookOpen, Droplet, Swords } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import type { Problem, WeekSet } from '../lib/types';
import { isWeekUnlocked } from '../data/weeks';
import DifficultyBadge from './DifficultyBadge';
import MathText from './MathText';
import SolutionEditor from './SolutionEditor';
import ProblemRating from './ProblemRating';
import ErrorReportButton from './ErrorReportButton';
import InteractiveProofWalk from './InteractiveProofWalk';
import ProblemDiscussion from './ProblemDiscussion';
import ProblemTags from './ProblemTags';
import ProofDuelArena from './ProofDuelArena';

interface Props {
  problem: Problem;
  week: WeekSet;
}

function isDbId(id: string): boolean {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
}

export default function ProblemCard({ problem, week }: Props) {
  const unlocked = isWeekUnlocked(week);
  const [openSolution, setOpenSolution] = useState(false);
  const [showConnection, setShowConnection] = useState(false);
  const [showProofWalk, setShowProofWalk] = useState(false);
  const [showDuel, setShowDuel] = useState(false);
  const [firstBlood, setFirstBlood] = useState<string | null>(null);

  useEffect(() => {
    if (!isDbId(problem.id)) return;
    (async () => {
      const { data } = await supabase
        .from('problems')
        .select('first_blood_user_name')
        .eq('id', problem.id)
        .maybeSingle();
      if (data) setFirstBlood((data as { first_blood_user_name: string | null }).first_blood_user_name);
    })();
  }, [problem.id]);

  return (
    <article className="overflow-hidden rounded-xl border border-ink-700 bg-ink-850/50 shadow-panel transition hover:border-ink-600">
      <header className="flex flex-col gap-3 border-b border-ink-700 bg-ink-900/60 p-5 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex items-start gap-4">
          <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-md border border-accent-400/40 bg-accent-400/10 font-mono text-lg font-semibold text-accent-300">
            {problem.index}
          </div>
          <div>
            <h3 className="font-serif text-xl text-ink-50">{problem.title}</h3>
            <div className="mt-1.5 flex flex-wrap items-center gap-2">
              <DifficultyBadge difficulty={problem.difficulty} />
              <span className="font-mono text-[10px] uppercase tracking-wider text-ink-500">
                {week.title}
              </span>
              {firstBlood && (
                <span className="flex items-center gap-1 rounded border border-red-500/30 bg-red-500/10 px-1.5 py-0.5 font-mono text-[9px] uppercase tracking-wider text-red-300">
                  <Droplet className="h-2.5 w-2.5" />
                  First blood: {firstBlood}
                </span>
              )}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <ProblemRating problemId={problem.id} />
          <ErrorReportButton problemId={problem.id} />
        </div>
      </header>

      <div className="space-y-4 p-5">
        <ProblemTags problemId={problem.id} editable={false} />

        <MathText>{problem.statement}</MathText>

        <div className="rounded-md border border-ink-700/70 bg-ink-900/40 p-3">
          <button
            onClick={() => setShowConnection((v) => !v)}
            className="focus-ring flex w-full items-center justify-between gap-2 text-left"
          >
            <span className="flex items-center gap-2 text-xs font-medium uppercase tracking-wider text-ink-300">
              <Lightbulb className="h-3.5 w-3.5 text-amber-400" />
              How this connects to the previous problem
            </span>
            {showConnection ? (
              <ChevronUp className="h-4 w-4 text-ink-400" />
            ) : (
              <ChevronDown className="h-4 w-4 text-ink-400" />
            )}
          </button>
          {showConnection && (
            <div className="mt-3 text-sm text-ink-300">
              <MathText>{problem.connection}</MathText>
            </div>
          )}
        </div>

        <div>
          <button
            onClick={() => setOpenSolution((v) => !v)}
            className="focus-ring flex w-full items-center justify-between gap-2 rounded-md border border-ink-700 bg-ink-900/40 px-3 py-2.5 text-left text-sm text-ink-200 transition hover:border-accent-400/40 hover:text-accent-200"
          >
            <span className="flex items-center gap-2">
              <BookOpen className="h-4 w-4 text-accent-400" />
              {openSolution ? 'Hide solution workspace' : 'Submit your solution'}
            </span>
            {openSolution ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
          </button>
          {openSolution && (
            <div className="mt-3">
              <SolutionEditor problemId={problem.id} weekId={week.id} />
            </div>
          )}
        </div>

        <div>
          <button
            onClick={() => setShowDuel((v) => !v)}
            className="focus-ring flex w-full items-center justify-between gap-2 rounded-md border border-ink-700 bg-ink-900/40 px-3 py-2.5 text-left text-sm text-ink-200 transition hover:border-accent-400/40 hover:text-accent-200"
          >
            <span className="flex items-center gap-2">
              <Swords className="h-4 w-4 text-red-400" />
              {showDuel ? 'Hide Proof Duel Arena' : 'Proof Duel Arena'}
            </span>
            {showDuel ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
          </button>
          {showDuel && (
            <div className="mt-3">
              <ProofDuelArena problem={problem} />
            </div>
          )}
        </div>

        <div className="relative">
          <div className="mb-2 flex items-center justify-between">
            <button
              onClick={() => setShowProofWalk((v) => !v)}
              className="focus-ring flex items-center gap-2 font-mono text-xs uppercase tracking-wider text-ink-300 hover:text-accent-300"
            >
              <BookOpen className="h-3.5 w-3.5 text-accent-400" />
              {showProofWalk ? 'Hide' : 'Show'} Interactive Proof-Walk
            </button>
            {!unlocked && (
              <span className="flex items-center gap-1.5 rounded border border-accent-400/30 bg-accent-400/10 px-2 py-0.5 font-mono text-[10px] uppercase tracking-wider text-accent-300">
                <Lock className="h-3 w-3" /> Locked
              </span>
            )}
          </div>
          {showProofWalk ? (
            <InteractiveProofWalk answer={problem.answer} proof={problem.proof} unlocked={unlocked} />
          ) : (
            <div className={`rounded-md border border-ink-700 bg-ink-900/60 p-4 ${!unlocked ? 'locked-blur' : ''}`}>
              <div className="mb-3">
                <div className="mb-1 font-mono text-[10px] uppercase tracking-wider text-ink-400">Answer</div>
                <MathText>{problem.answer}</MathText>
              </div>
              <div>
                <div className="mb-1 font-mono text-[10px] uppercase tracking-wider text-ink-400">Proof</div>
                <MathText>{problem.proof}</MathText>
              </div>
            </div>
          )}
          {!unlocked && !showProofWalk && (
            <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
              <div className="pointer-events-auto rounded-md border border-accent-400/40 bg-ink-900/90 px-4 py-2 text-center text-xs text-ink-300 shadow-glow">
                <Lock className="mb-1 inline h-3.5 w-3.5 text-accent-400" />
                <div>Answers unlock when the weekly timer hits zero.</div>
              </div>
            </div>
          )}
        </div>

        <ProblemDiscussion problemId={problem.id} />
      </div>
    </article>
  );
}

src/components/ProblemDiscussion.tsx:
import { useEffect, useState } from 'react';
import { MessageSquare, Loader2, Send, ChevronDown, ChevronUp, Trash2, Reply, User } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { useAuth, useDisplayName } from '../lib/AuthContext';
import MathText from './MathText';

interface Discussion {
  id: string;
  title: string;
  body: string;
  author_id: string;
  author_name: string;
  created_at: string;
  reply_count?: number;
}

interface Reply {
  id: string;
  discussion_id: string;
  parent_id: string | null;
  body: string;
  author_id: string;
  author_name: string;
  created_at: string;
  children?: Reply[];
}

interface Props {
  problemId: string;
}

export default function ProblemDiscussion({ problemId }: Props) {
  const { user, configured } = useAuth();
  const displayName = useDisplayName();
  const [loading, setLoading] = useState(true);
  const [discussions, setDiscussions] = useState<Discussion[]>([]);
  const [expanded, setExpanded] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newBody, setNewBody] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [activeDiscussion, setActiveDiscussion] = useState<Discussion | null>(null);
  const [replies, setReplies] = useState<Reply[]>([]);
  const [replyBodies, setReplyBodies] = useState<Record<string, string>>({});
  const [replyingTo, setReplyingTo] = useState<string | null>(null);

  useEffect(() => {
    if (!configured) {
      setLoading(false);
      return;
    }
    loadDiscussions();
  }, [problemId, configured]);

  const loadDiscussions = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('problem_discussions')
      .select('id, title, body, author_id, author_name, created_at')
      .eq('problem_id', problemId)
      .order('created_at', { ascending: false });

    if (!error && data) {
      const withCounts = await Promise.all(
        (data as Discussion[]).map(async (d) => {
          const { count } = await supabase
            .from('problem_discussion_replies')
            .select('id', { count: 'exact', head: true })
            .eq('discussion_id', d.id);
          return { ...d, reply_count: count ?? 0 };
        })
      );
      setDiscussions(withCounts);
    }
    setLoading(false);
  };

  const loadReplies = async (discussionId: string) => {
    const { data } = await supabase
      .from('problem_discussion_replies')
      .select('id, discussion_id, parent_id, body, author_id, author_name, created_at')
      .eq('discussion_id', discussionId)
      .order('created_at', { ascending: true });

    if (data) {
      setReplies(buildReplyTree(data as Reply[]));
    }
  };

  const buildReplyTree = (flat: Reply[]): Reply[] => {
    const byId = new Map<string, Reply>();
    flat.forEach((r) => byId.set(r.id, { ...r, children: [] }));
    const roots: Reply[] = [];
    flat.forEach((r) => {
      const node = byId.get(r.id)!;
      if (r.parent_id && byId.has(r.parent_id)) {
        byId.get(r.parent_id)!.children!.push(node);
      } else {
        roots.push(node);
      }
    });
    return roots;
  };

  const createDiscussion = async () => {
    if (!user || !newTitle.trim() || !newBody.trim()) return;
    setSubmitting(true);
    const { data, error } = await supabase
      .from('problem_discussions')
      .insert({
        problem_id: problemId,
        title: newTitle.trim(),
        body: newBody.trim(),
        author_id: user.id,
        author_name: displayName,
      })
      .select('id, title, body, author_id, author_name, created_at')
      .maybeSingle();

    if (error) {
      console.error(error);
    } else if (data) {
      setDiscussions([{ ...(data as Discussion), reply_count: 0 }, ...discussions]);
      setNewTitle('');
      setNewBody('');
    }
    setSubmitting(false);
  };

  const createReply = async (discussionId: string, parentId: string | null) => {
    const body = parentId ? replyBodies[parentId] : replyBodies['root'];
    if (!user || !body?.trim()) return;
    setSubmitting(true);
    await supabase.from('problem_discussion_replies').insert({
      discussion_id: discussionId,
      parent_id: parentId,
      body: body.trim(),
      author_id: user.id,
      author_name: displayName,
    });
    await loadReplies(discussionId);
    setReplyBodies((prev) => ({ ...prev, [parentId ?? 'root']: '' }));
    setReplyingTo(null);
    setSubmitting(false);

    setDiscussions((prev) =>
      prev.map((d) =>
        d.id === discussionId ? { ...d, reply_count: (d.reply_count ?? 0) + 1 } : d
      )
    );
  };

  const deleteDiscussion = async (id: string) => {
    if (!confirm('Delete this discussion?')) return;
    await supabase.from('problem_discussions').delete().eq('id', id);
    setDiscussions(discussions.filter((d) => d.id !== id));
    setActiveDiscussion(null);
  };

  const deleteReply = async (id: string, discussionId: string) => {
    if (!confirm('Delete this reply?')) return;
    await supabase.from('problem_discussion_replies').delete().eq('id', id);
    await loadReplies(discussionId);
    setDiscussions((prev) =>
      prev.map((d) =>
        d.id === discussionId ? { ...d, reply_count: Math.max(0, (d.reply_count ?? 1) - 1) } : d
      )
    );
  };

  const ReplyItem = ({ reply, depth = 0 }: { reply: Reply; depth?: number }) => (
    <div className={`${depth > 0 ? 'ml-5 border-l-2 border-ink-700 pl-3' : ''} py-2`}>
      <div className="flex items-center justify-between text-xs text-ink-400">
        <span className="flex items-center gap-1.5 font-mono text-accent-300">
          <User className="h-3 w-3" />
          {reply.author_name}
        </span>
        <span>{new Date(reply.created_at).toLocaleDateString()}</span>
      </div>
      <div className="mt-1.5 text-sm">
        <MathText>{reply.body}</MathText>
      </div>
      <div className="mt-1.5 flex items-center gap-2">
        {user && reply.author_id !== user.id && (
          <button
            onClick={() => setReplyingTo(replyingTo === reply.id ? null : reply.id)}
            className="flex items-center gap-1 text-xs text-ink-500 hover:text-accent-300"
          >
            <Reply className="h-3 w-3" /> Reply
          </button>
        )}
        {user && reply.author_id === user.id && (
          <button
            onClick={() => deleteReply(reply.id, activeDiscussion?.id ?? '')}
            className="flex items-center gap-1 text-xs text-ink-500 hover:text-red-300"
          >
            <Trash2 className="h-3 w-3" /> Delete
          </button>
        )}
      </div>
      {replyingTo === reply.id && (
        <div className="mt-2 space-y-2">
          <textarea
            value={replyBodies[reply.id] ?? ''}
            onChange={(e) => setReplyBodies((prev) => ({ ...prev, [reply.id]: e.target.value }))}
            rows={2}
            className="focus-ring w-full rounded-md border border-ink-700 bg-ink-900 px-2 py-1.5 text-xs text-ink-100"
            placeholder="Write a reply..."
          />
          <button
            onClick={() => createReply(activeDiscussion!.id, reply.id)}
            disabled={submitting || !replyBodies[reply.id]?.trim()}
            className="focus-ring flex items-center gap-1 rounded-md border border-accent-400 bg-accent-400/15 px-2 py-1 text-xs text-accent-200 disabled:opacity-50"
          >
            <Send className="h-3 w-3" /> Reply
          </button>
        </div>
      )}
      {reply.children?.map((c) => (
        <ReplyItem key={c.id} reply={c} depth={depth + 1} />
      ))}
    </div>
  );

  if (activeDiscussion) {
    return (
      <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4">
        <button
          onClick={() => setActiveDiscussion(null)}
          className="flex items-center gap-1 text-xs text-ink-400 hover:text-accent-200"
        >
          {'<'} Back to discussions
        </button>

        <div className="mt-4 border-b border-ink-700 pb-4">
          <h4 className="font-serif text-lg text-ink-50">{activeDiscussion.title}</h4>
          <div className="mt-1 flex items-center gap-2 text-xs text-ink-400">
            <span className="font-mono text-accent-300">{activeDiscussion.author_name}</span>
            <span>{new Date(activeDiscussion.created_at).toLocaleDateString()}</span>
          </div>
          <div className="mt-2 text-sm text-ink-300">
            <MathText>{activeDiscussion.body}</MathText>
          </div>
          {user && activeDiscussion.author_id === user.id && (
            <button
              onClick={() => deleteDiscussion(activeDiscussion.id)}
              className="mt-2 flex items-center gap-1 text-xs text-ink-500 hover:text-red-300"
            >
              <Trash2 className="h-3 w-3" /> Delete discussion
            </button>
          )}
        </div>

        <div className="mt-4 space-y-2">
          <div className="flex items-center gap-2 text-xs text-ink-400">
            <MessageSquare className="h-3.5 w-3.5" />
            {replies.length} replies
          </div>

          {replies.map((r) => (
            <ReplyItem key={r.id} reply={r} />
          ))}

          {user && (
            <div className="mt-4 space-y-2 rounded-md border border-ink-700 bg-ink-900/50 p-3">
              <textarea
                value={replyBodies['root'] ?? ''}
                onChange={(e) => setReplyBodies((prev) => ({ ...prev, root: e.target.value }))}
                rows={3}
                className="focus-ring w-full rounded-md border border-ink-700 bg-ink-900 px-2 py-1.5 text-xs text-ink-100 resize-y"
                placeholder="Write a reply..."
              />
              <button
                onClick={() => createReply(activeDiscussion.id, null)}
                disabled={submitting || !(replyBodies['root']?.trim())}
                className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-3 py-1.5 text-xs text-accent-200 disabled:opacity-50"
              >
                <Send className="h-3.5 w-3.5" /> Post Reply
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <button
        onClick={() => setExpanded(!expanded)}
        className="focus-ring flex w-full items-center justify-between gap-2 rounded-md border border-ink-700 bg-ink-900/40 px-3 py-2.5 text-left text-sm text-ink-200 transition hover:border-accent-400/40 hover:text-accent-200"
      >
        <span className="flex items-center gap-2">
          <MessageSquare className="h-4 w-4 text-accent-400" />
          {expanded ? 'Hide discussion' : 'Problem Discussion'}
          {discussions.length > 0 && (
            <span className="rounded-full border border-ink-600 bg-ink-800 px-1.5 py-0.5 font-mono text-[10px] text-ink-400">
              {discussions.length}
            </span>
          )}
        </span>
        {expanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
      </button>

      {expanded && (
        <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4 space-y-4">
          {user && (
            <div className="space-y-2">
              <input
                type="text"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
                className="focus-ring w-full rounded-md border border-ink-700 bg-ink-900 px-3 py-2 text-sm text-ink-100 placeholder:text-ink-500"
                placeholder="Discussion title..."
              />
              <textarea
                value={newBody}
                onChange={(e) => setNewBody(e.target.value)}
                rows={3}
                className="focus-ring w-full rounded-md border border-ink-700 bg-ink-900 px-3 py-2 text-sm text-ink-100 placeholder:text-ink-500 resize-y"
                placeholder="Start a discussion about this problem..."
              />
              <button
                onClick={createDiscussion}
                disabled={submitting || !newTitle.trim() || !newBody.trim()}
                className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-3 py-1.5 text-xs font-semibold text-accent-200 transition hover:bg-accent-400/25 disabled:opacity-50"
              >
                <Send className="h-3.5 w-3.5" />
                Start Discussion
              </button>
            </div>
          )}

          {loading ? (
            <div className="flex items-center gap-2 text-sm text-ink-400">
              <Loader2 className="h-4 w-4 animate-spin" /> Loading...
            </div>
          ) : discussions.length === 0 ? (
            <div className="text-sm text-ink-400 text-center py-4">
              No discussions yet. Be the first to start one!
            </div>
          ) : (
            <div className="space-y-3">
              {discussions.map((d) => (
                <button
                  key={d.id}
                  onClick={async () => {
                    setActiveDiscussion(d);
                    await loadReplies(d.id);
                  }}
                  className="w-full rounded-md border border-ink-700 bg-ink-900/50 p-3 text-left hover:border-ink-600 transition text-sm"
                >
                  <div className="font-medium text-ink-100">{d.title}</div>
                  <div className="mt-1 flex items-center gap-2 text-xs text-ink-400">
                    <span className="font-mono text-accent-300">{d.author_name}</span>
                    <span>{new Date(d.created_at).toLocaleDateString()}</span>
                    <span className="flex items-center gap-1">
                      <MessageSquare className="h-3 w-3" />
                      {d.reply_count ?? 0}
                    </span>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

src/components/ProblemRating.tsx:
import { useEffect, useState } from 'react';
import { Star, Loader2 } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { useAuth } from '../lib/AuthContext';

interface Props {
  problemId: string;
}

export default function ProblemRating({ problemId }: Props) {
  const { user, configured } = useAuth();
  const [myRating, setMyRating] = useState<number | null>(null);
  const [avgRating, setAvgRating] = useState<number | null>(null);
  const [count, setCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [hovered, setHovered] = useState<number | null>(null);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (!configured) {
      setLoading(false);
      return;
    }
    let cancelled = false;
    (async () => {
      setLoading(true);
      const { data: ratings } = await supabase
        .from('problem_ratings')
        .select('rating, user_id')
        .eq('problem_id', problemId);

      if (!cancelled && ratings) {
        const ratingsList = ratings as { rating: number; user_id: string }[];
        const sum = ratingsList.reduce((a, b) => a + b.rating, 0);
        setCount(ratingsList.length);
        setAvgRating(ratingsList.length > 0 ? sum / ratingsList.length : null);

        if (user) {
          const mine = ratingsList.find((r) => r.user_id === user.id);
          setMyRating(mine ? mine.rating : null);
        }
      }
      setLoading(false);
    })();
    return () => {
      cancelled = true;
    };
  }, [problemId, user, configured]);

  const setRating = async (rating: number) => {
    if (!user || !configured) return;
    setSubmitting(true);
    try {
      if (myRating) {
        const { error } = await supabase
          .from('problem_ratings')
          .update({ rating, updated_at: new Date().toISOString() })
          .eq('problem_id', problemId)
          .eq('user_id', user.id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('problem_ratings')
          .insert({ problem_id: problemId, user_id: user.id, rating });
        if (error) throw error;
      }

      setMyRating(rating);

      const { data: ratings } = await supabase
        .from('problem_ratings')
        .select('rating')
        .eq('problem_id', problemId);

      if (ratings) {
        const ratingsList = ratings as { rating: number }[];
        const sum = ratingsList.reduce((a, b) => a + b.rating, 0);
        setCount(ratingsList.length);
        setAvgRating(ratingsList.length > 0 ? sum / ratingsList.length : null);
      }
    } catch (err) {
      console.error('Failed to set rating:', err);
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center gap-1.5 text-xs text-ink-400">
        <Loader2 className="h-3.5 w-3.5 animate-spin" />
      </div>
    );
  }

  const displayRating = hovered ?? myRating ?? Math.round(avgRating ?? 0);

  return (
    <div className="flex flex-wrap items-center gap-2">
      <div className="flex items-center gap-0.5">
        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            onClick={() => user && setRating(star)}
            onMouseEnter={() => setHovered(star)}
            onMouseLeave={() => setHovered(null)}
            disabled={!user || !configured || submitting}
            className={`focus-ring rounded-sm p-0.5 transition ${
              !user ? 'cursor-not-allowed opacity-60' : 'hover:scale-110'
            }`}
            title={user ? `Rate ${star} star${star > 1 ? 's' : ''}` : 'Sign in to rate'}
          >
            <Star
              className={`h-4 w-4 transition ${
                star <= displayRating
                  ? 'fill-amber-400 text-amber-400'
                  : 'text-ink-600'
              }`}
            />
          </button>
        ))}
      </div>
      {count > 0 && (
        <span className="text-xs text-ink-400">
          {avgRating?.toFixed(1)} ({count} rating{count !== 1 ? 's' : ''})
        </span>
      )}
      {!user && (
        <span className="text-xs text-ink-500">Sign in to rate</span>
      )}
    </div>
  );
}

