import { useEffect, useState } from 'react';
import { supabase } from '../lib/supabaseClient';
import { Tag, X, Plus } from 'lucide-react';

export const MATH_TAGS = [
  { id: 'pigeonhole', name: 'Pigeonhole Principle', subject: 'combinatorics' },
  { id: 'stars-bars', name: 'Stars and Bars', subject: 'combinatorics' },
  { id: 'inclusion-exclusion', name: 'Inclusion-Exclusion', subject: 'combinatorics' },
  { id: 'bijection', name: 'Bijection', subject: 'combinatorics' },
  { id: 'induction', name: 'Induction', subject: 'algebra' },
  { id: 'recurrence', name: 'Recurrence Relations', subject: 'algebra' },
  { id: 'gen-func', name: 'Generating Functions', subject: 'algebra' },
  { id: 'vieta', name: "Vieta's Formulas", subject: 'algebra' },
  { id: 'am-gm', name: 'AM-GM Inequality', subject: 'inequalities' },
  { id: 'cauchy', name: 'Cauchy-Schwarz', subject: 'inequalities' },
  { id: 'smoothing', name: 'Smoothing', subject: 'inequalities' },
  { id: 'lte', name: 'LTE Lemma', subject: 'number_theory' },
  { id: 'fermat', name: "Fermat's Little Theorem", subject: 'number_theory' },
  { id: 'euler-totient', name: "Euler's Totient", subject: 'number_theory' },
  { id: 'modular', name: 'Modular Arithmetic', subject: 'number_theory' },
  { id: 'diophantine', name: 'Diophantine Equations', subject: 'number_theory' },
  { id: 'inversion', name: 'Inversion', subject: 'geometry' },
  { id: 'homothety', name: 'Homothety', subject: 'geometry' },
  { id: 'power-point', name: 'Power of a Point', subject: 'geometry' },
  { id: 'ceva-menelaus', name: 'Ceva & Menelaus', subject: 'geometry' },
  { id: 'trig-geo', name: 'Trigonometry', subject: 'geometry' },
  { id: 'complex-geo', name: 'Complex Numbers', subject: 'geometry' },
  { id: 'combinatorial-geo', name: 'Combinatorial Geometry', subject: 'geometry' },
  { id: 'limits', name: 'Limits', subject: 'analysis' },
  { id: 'integrals', name: 'Integration', subject: 'analysis' },
  { id: 'derivatives', name: 'Differentiation', subject: 'analysis' },
] as const;

interface Props {
  problemId: string;
  editable?: boolean;
  filterable?: boolean;
  selectedTags?: string[];
  onTagClick?: (tag: string) => void;
}

export default function ProblemTags({ problemId, editable = false, filterable = false, selectedTags, onTagClick }: Props) {
  const [tags, setTags] = useState<string[]>([]);
  const [allTags, setAllTags] = useState<string[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newTag, setNewTag] = useState('');

  useEffect(() => {
    if (problemId) {
      loadTags();
    }
    if (filterable) {
      loadAllTags();
    }
  }, [problemId, filterable]);

  const loadTags = async () => {
    const { data } = await supabase
      .from('problem_tags')
      .select('tag')
      .eq('problem_id', problemId);
    if (data) {
      setTags(data.map((t) => t.tag));
    }
  };

  const loadAllTags = async () => {
    const { data } = await supabase
      .from('problem_tags')
      .select('tag');
    if (data) {
      setAllTags([...new Set(data.map((t) => t.tag))]);
    }
  };

  const addTag = async (tag: string) => {
    if (!tag.trim() || tags.includes(tag)) return;
    const { error } = await supabase
      .from('problem_tags')
      .insert({ problem_id: problemId, tag: tag.trim() });
    if (!error) {
      setTags([...tags, tag.trim()]);
      setNewTag('');
      setShowAdd(false);
    }
  };

  const removeTag = async (tag: string) => {
    const { error } = await supabase
      .from('problem_tags')
      .delete()
      .eq('problem_id', problemId)
      .eq('tag', tag);
    if (!error) {
      setTags(tags.filter((t) => t !== tag));
    }
  };

  const getTagStyle = (tag: string) => {
    const tagInfo = MATH_TAGS.find((t) => t.id === tag.toLowerCase().replace(/\s|-/g, '') || t.name === tag);
    const subject = tagInfo?.subject || 'general';
    const styles: Record<string, string> = {
      combinatorics: 'bg-emerald-500/15 text-emerald-300 border-emerald-500/40',
      algebra: 'bg-violet-500/15 text-violet-300 border-violet-500/40',
      inequalities: 'bg-amber-500/15 text-amber-300 border-amber-500/40',
      number_theory: 'bg-amber-500/15 text-amber-300 border-amber-500/40',
      geometry: 'bg-sky-500/15 text-sky-300 border-sky-500/40',
      analysis: 'bg-rose-500/15 text-rose-300 border-rose-500/40',
    };
    return styles[subject] || 'bg-ink-700/50 text-ink-300 border-ink-600';
  };

  if (filterable && !problemId) {
    return (
      <div className="flex flex-wrap gap-2">
        {allTags.map((tag) => (
          <button
            key={tag}
            onClick={() => onTagClick?.(tag)}
            className={`rounded-full border px-2 py-0.5 text-xs transition ${
              selectedTags?.includes(tag)
                ? 'bg-accent-400/20 text-accent-200 border-accent-400/40'
                : getTagStyle(tag) + ' hover:brightness-110'
            }`}
          >
            {tag}
          </button>
        ))}
      </div>
    );
  }

  return (
    <div className="flex flex-wrap items-center gap-1.5">
      <Tag className="h-3.5 w-3.5 text-ink-500" />
      {tags.map((tag) => (
        <span
          key={tag}
          onClick={() => filterable && onTagClick?.(tag)}
          className={`rounded-full border px-2 py-0.5 text-xs ${getTagStyle(tag)} ${
            filterable ? 'cursor-pointer hover:brightness-110' : ''
          }`}
        >
          {tag}
          {editable && (
            <button
              onClick={(e) => {
                e.stopPropagation();
                removeTag(tag);
              }}
              className="ml-1 text-ink-400 hover:text-red-300"
            >
              <X className="h-3 w-3" />
            </button>
          )}
        </span>
      ))}
      {editable && (
        <>
          {showAdd ? (
            <div className="flex items-center gap-1">
              <input
                type="text"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && addTag(newTag)}
                className="w-24 rounded border border-ink-700 bg-ink-900 px-2 py-0.5 text-xs text-ink-100"
                placeholder="Tag..."
                autoFocus
              />
              <button
                onClick={() => addTag(newTag)}
                className="rounded bg-accent-400/20 px-1.5 py-0.5 text-xs text-accent-200"
              >
                Add
              </button>
              <button
                onClick={() => setShowAdd(false)}
                className="text-xs text-ink-500 hover:text-ink-300"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          ) : (
            <button
              onClick={() => setShowAdd(true)}
              className="rounded-full border border-dashed border-ink-600 px-2 py-0.5 text-xs text-ink-500 hover:border-accent-400/40 hover:text-accent-200"
            >
              <Plus className="h-3 w-3" />
            </button>
          )}
        </>
      )}
      {tags.length === 0 && !editable && (
        <span className="text-xs text-ink-500">No tags</span>
      )}
    </div>
  );
}

src/components/ProfileMenu.tsx:
import { useEffect, useRef, useState } from 'react';
import { ChevronDown, User, BarChart3, Settings, LogOut, Crown, Layers } from 'lucide-react';
import { useAuth } from '../lib/AuthContext';

interface Props {
  navigate: (to: string) => void;
  onSignIn: () => void;
  onSignUp: () => void;
}

export default function ProfileMenu({ navigate, onSignIn, onSignUp }: Props) {
  const { user, signOut, isHost } = useAuth();
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const onDoc = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setOpen(false);
    };
    document.addEventListener('mousedown', onDoc);
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('mousedown', onDoc);
      document.removeEventListener('keydown', onKey);
    };
  }, [open]);

  if (!user) {
    return (
      <div className="hidden items-center gap-2 md:flex">
        <button
          onClick={onSignIn}
          className="focus-ring rounded-md px-3 py-1.5 text-sm text-ink-200 transition hover:text-ink-50"
        >
          Sign in
        </button>
        <button
          onClick={onSignUp}
          className="focus-ring rounded-md border border-accent-400 bg-accent-400/15 px-3 py-1.5 text-sm font-semibold text-accent-200 transition hover:bg-accent-400/25"
        >
          Join
        </button>
      </div>
    );
  }

  const name =
    (user.user_metadata as { display_name?: string })?.display_name ||
    user.email?.split('@')[0] ||
    'mathlete';

  return (
    <div className="relative hidden md:block" ref={ref}>
      <button
        onClick={() => setOpen((v) => !v)}
        className="focus-ring flex items-center gap-2 rounded-md border border-ink-700 bg-ink-850 px-2.5 py-1.5 text-xs text-ink-200 transition hover:border-ink-600"
      >
        <span className="flex h-6 w-6 items-center justify-center rounded-full border border-accent-400/40 bg-accent-400/10 font-mono text-[10px] font-semibold text-accent-300">
          {name[0]?.toUpperCase()}
        </span>
        <span className="max-w-[10rem] truncate font-mono">{name}</span>
        {isHost && <Crown className="h-3 w-3 text-accent-400" />}
        <ChevronDown className={`h-3.5 w-3.5 text-ink-400 transition ${open ? 'rotate-180' : ''}`} />
      </button>

      {open && (
        <div className="absolute right-0 z-50 mt-2 w-60 animate-fade-in overflow-hidden rounded-lg border border-ink-700 bg-ink-900 shadow-panel">
          <div className="border-b border-ink-700 px-4 py-3">
            <div className="flex items-center gap-2">
              <span className="flex h-8 w-8 items-center justify-center rounded-full border border-accent-400/40 bg-accent-400/10 font-mono text-sm font-semibold text-accent-300">
                {name[0]?.toUpperCase()}
              </span>
              <div className="min-w-0">
                <div className="truncate text-sm text-ink-100">{name}</div>
                <div className="truncate text-[10px] text-ink-500">{user.email}</div>
              </div>
            </div>
            {isHost && (
              <span className="mt-2 inline-flex items-center gap-1 rounded border border-accent-400/30 bg-accent-400/10 px-1.5 py-0.5 font-mono text-[9px] uppercase tracking-wider text-accent-300">
                <Crown className="h-2.5 w-2.5" /> Host
              </span>
            )}
          </div>
          <div className="p-1.5">
            <MenuItem icon={<BarChart3 className="h-4 w-4" />} label="Account stats" onClick={() => { setOpen(false); navigate('/me'); }} />
            {isHost && (
              <MenuItem icon={<Layers className="h-4 w-4" />} label="Host dashboard" onClick={() => { setOpen(false); navigate('/host'); }} />
            )}
            <MenuItem icon={<User className="h-4 w-4" />} label="My community sets" onClick={() => { setOpen(false); navigate('/community'); }} />
            <MenuItem icon={<Settings className="h-4 w-4" />} label="Profile settings" onClick={() => { setOpen(false); navigate('/me/settings'); }} />
            <div className="my-1.5 border-t border-ink-700" />
            <MenuItem
              icon={<LogOut className="h-4 w-4" />}
              label="Sign out"
              danger
              onClick={() => { setOpen(false); signOut(); }}
            />
          </div>
        </div>
      )}
    </div>
  );
}

function MenuItem({
  icon,
  label,
  onClick,
  danger,
}: {
  icon: React.ReactNode;
  label: string;
  onClick: () => void;
  danger?: boolean;
}) {
  return (
    <button
      onClick={onClick}
      className={`focus-ring flex w-full items-center gap-2.5 rounded-md px-3 py-2 text-left text-sm transition ${
        danger ? 'text-ink-300 hover:bg-red-500/10 hover:text-red-300' : 'text-ink-200 hover:bg-ink-800 hover:text-ink-50'
      }`}
    >
      <span className={danger ? 'text-red-400' : 'text-accent-400'}>{icon}</span>
      {label}
    </button>
  );
}

src/components/ProofDuelArena.tsx:
import { useEffect, useState } from 'react';
import { Swords, Loader2, Send, Trophy, Users, Clock, ChevronRight, AlertCircle, Crown } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { useAuth, useDisplayName } from '../lib/AuthContext';
import MathText from './MathText';
import type { Problem } from '../lib/types';

interface Duel {
  id: string;
  problem_id: string;
  challenger_id: string;
  challenger_name: string;
  challenger_solution?: string;
  defender_id?: string;
  defender_name?: string;
  defender_solution?: string;
  status: 'open' | 'matched' | 'voting' | 'completed' | 'expired';
  winner_id?: string;
  votes_challenger: number;
  votes_defender: number;
  created_at: string;
}

interface Props {
  problem: Problem;
}

export default function ProofDuelArena({ problem }: Props) {
  const { user, configured } = useAuth();
  const displayName = useDisplayName();
  const [openDuels, setOpenDuels] = useState<Duel[]>([]);
  const [myDuels, setMyDuels] = useState<Duel[]>([]);
  const [loading, setLoading] = useState(true);
  const [creating, setCreating] = useState(false);
  const [joining, setJoining] = useState(false);
  const [selectedDuel, setSelectedDuel] = useState<Duel | null>(null);
  const [solution, setSolution] = useState('');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!configured || !user) {
      setLoading(false);
      return;
    }
    loadDuels();
  }, [problem.id, user, configured]);

  const loadDuels = async () => {
    setLoading(true);
    const { data: openData } = await supabase
      .from('proof_duels')
      .select('*')
      .eq('problem_id', problem.id)
      .eq('status', 'open')
      .neq('challenger_id', user!.id);

    const { data: myData } = await supabase
      .from('proof_duels')
      .select('*')
      .eq('problem_id', problem.id)
      .or(`challenger_id.eq.${user!.id},defender_id.eq.${user!.id}`)
      .order('created_at', { ascending: false });

    if (openData) setOpenDuels(openData as Duel[]);
    if (myData) setMyDuels(myData as Duel[]);
    setLoading(false);
  };

  const createDuel = async () => {
    if (!user || !solution.trim()) return;
    setCreating(true);
    setError(null);
    const { error: insertError } = await supabase.from('proof_duels').insert({
      problem_id: problem.id,
      challenger_id: user.id,
      challenger_name: displayName,
      challenger_solution: solution.trim(),
    });

    if (insertError) {
      setError(insertError.message);
    } else {
      setSolution('');
      await loadDuels();
    }
    setCreating(false);
  };

  const joinDuel = async (duel: Duel) => {
    if (!user || !solution.trim() || duel.defender_id) return;
    setJoining(true);
    setError(null);
    const { error: updateError } = await supabase
      .from('proof_duels')
      .update({
        defender_id: user.id,
        defender_name: displayName,
        defender_solution: solution.trim(),
        status: 'voting',
      })
      .eq('id', duel.id);

    if (updateError) {
      setError(updateError.message);
    } else {
      setSolution('');
      await loadDuels();
    }
    setJoining(false);
  };

  const vote = async (duelId: string, voteForId: string) => {
    if (!user) return;
    await supabase.from('duel_votes').insert({
      duel_id: duelId,
      voter_id: user.id,
      vote_for: voteForId,
    });
    await loadDuels();
  };

  if (!configured) {
    return (
      <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4 text-sm text-ink-400">
        <AlertCircle className="mb-1 h-4 w-4 text-yellow-400" />
        Proof Duels require a connected database.
      </div>
    );
  }

  if (!user) {
    return (
      <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4 text-sm text-ink-400">
        <Users className="mb-1 h-4 w-4 text-accent-400" />
        Sign in to participate in Proof Duels.
      </div>
    );
  }

  if (selectedDuel) {
    return (
      <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4 space-y-4">
        <button
          onClick={() => setSelectedDuel(null)}
          className="text-xs text-ink-400 hover:text-accent-200"
        >
          {'<'} Back to duels
        </button>

        <div className="grid gap-4 md:grid-cols-2">
          <div className="rounded-lg border border-ink-700 bg-ink-900/50 p-4">
            <div className="flex items-center gap-2 text-sm text-ink-200 mb-2">
              <Trophy className="h-4 w-4 text-accent-400" />
              Player 1: {selectedDuel.challenger_name}
              {selectedDuel.winner_id === selectedDuel.challenger_id && (
                <Crown className="h-4 w-4 text-amber-400" />
              )}
            </div>
            <div className="rounded-md border border-ink-700 bg-ink-900 p-3 text-sm">
              <MathText>{selectedDuel.challenger_solution || 'No solution submitted'}</MathText>
            </div>
            <div className="mt-2 flex items-center gap-2">
              <div className="flex-1 h-2 rounded-full bg-ink-800 overflow-hidden">
                <div
                  className="h-full bg-accent-400"
                  style={{ width: `${(selectedDuel.votes_challenger / Math.max(1, selectedDuel.votes_challenger + selectedDuel.votes_defender)) * 100}%` }}
                />
              </div>
              <span className="text-xs text-ink-400">{selectedDuel.votes_challenger} votes</span>
            </div>
          </div>

          <div className="rounded-lg border border-ink-700 bg-ink-900/50 p-4">
            <div className="flex items-center gap-2 text-sm text-ink-200 mb-2">
              <Trophy className="h-4 w-4 text-accent-400" />
              Player 2: {selectedDuel.defender_name || 'Waiting...'}
              {selectedDuel.winner_id === selectedDuel.defender_id && (
                <Crown className="h-4 w-4 text-amber-400" />
              )}
            </div>
            {selectedDuel.defender_solution ? (
              <>
                <div className="rounded-md border border-ink-700 bg-ink-900 p-3 text-sm">
                  <MathText>{selectedDuel.defender_solution}</MathText>
                </div>
                <div className="mt-2 flex items-center gap-2">
                  <div className="flex-1 h-2 rounded-full bg-ink-800 overflow-hidden">
                    <div
                      className="h-full bg-accent-400"
                      style={{ width: `${(selectedDuel.votes_defender / Math.max(1, selectedDuel.votes_challenger + selectedDuel.votes_defender)) * 100}%` }}
                    />
                  </div>
                  <span className="text-xs text-ink-400">{selectedDuel.votes_defender} votes</span>
                </div>
              </>
            ) : (
              <div className="rounded-md border border-dashed border-ink-600 bg-ink-900/30 p-4 text-center text-sm text-ink-400">
                Waiting for opponent
              </div>
            )}
          </div>
        </div>

        {selectedDuel.status === 'voting' && selectedDuel.defender_solution && (
          <div className="flex justify-center gap-3">
            <button
              onClick={() => vote(selectedDuel.id, selectedDuel.challenger_id)}
              className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-4 py-2 text-sm text-accent-200 hover:bg-accent-400/25"
            >
              Vote for {selectedDuel.challenger_name}
            </button>
            <button
              onClick={() => vote(selectedDuel.id, selectedDuel.defender_id!)}
              className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-4 py-2 text-sm text-accent-200 hover:bg-accent-400/25"
            >
              Vote for {selectedDuel.defender_name}
            </button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h4 className="flex items-center gap-2 font-mono text-xs uppercase tracking-wider text-ink-300">
          <Swords className="h-3.5 w-3.5 text-accent-400" />
          Proof Duel Arena
        </h4>
      </div>

      <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4 space-y-4">
        <div className="space-y-2">
          <div className="text-sm text-ink-400">Challenge someone to an elegant-off!</div>
          <textarea
            value={solution}
            onChange={(e) => setSolution(e.target.value)}
            rows={5}
            className="focus-ring w-full rounded-md border border-ink-700 bg-ink-900 p-3 text-sm text-ink-100 font-mono"
            placeholder="Write your proof here..."
          />
          {error && (
            <div className="text-xs text-red-300">{error}</div>
          )}
        </div>

        <div className="flex flex-wrap gap-2">
          <button
            onClick={createDuel}
            disabled={creating || !solution.trim()}
            className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-3 py-1.5 text-xs font-semibold text-accent-200 hover:bg-accent-400/25 disabled:opacity-50"
          >
            {creating ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Swords className="h-3.5 w-3.5" />}
            Open a Duel
          </button>
        </div>

        {loading ? (
          <div className="flex items-center gap-2 text-sm text-ink-400">
            <Loader2 className="h-4 w-4 animate-spin" /> Loading duels...
          </div>
        ) : (
          <>
            {openDuels.length > 0 && (
              <div className="space-y-2">
                <div className="text-xs uppercase tracking-wider text-ink-500">Open Challenges</div>
                {openDuels.map((d) => (
                  <div key={d.id} className="flex items-center justify-between rounded-md border border-ink-700 bg-ink-900/50 p-3">
                    <div>
                      <div className="text-sm text-ink-200">{d.challenger_name} is waiting for an opponent</div>
                      <div className="text-xs text-ink-500">
                        <Clock className="inline h-3 w-3 mr-1" />
                        {new Date(d.created_at).toLocaleDateString()}
                      </div>
                    </div>
                    <button
                      onClick={() => joinDuel(d)}
                      disabled={joining || !solution.trim()}
                      className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-3 py-1.5 text-xs text-accent-200 hover:bg-accent-400/25 disabled:opacity-50"
                    >
                      {joining ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Send className="h-3.5 w-3.5" />}
                      Accept
                    </button>
                  </div>
                ))}
              </div>
            )}

            {myDuels.length > 0 && (
              <div className="space-y-2">
                <div className="text-xs uppercase tracking-wider text-ink-500">Your Duels</div>
                {myDuels.map((d) => (
                  <button
                    key={d.id}
                    onClick={() => setSelectedDuel(d)}
                    className="w-full flex items-center justify-between rounded-md border border-ink-700 bg-ink-900/50 p-3 hover:border-ink-600 transition text-left"
                  >
                    <div>
                      <div className="flex items-center gap-2 text-sm text-ink-200">
                        {d.challenger_id === user!.id ? `vs ${d.defender_name || 'Waiting...'}` : `vs ${d.challenger_name}`}
                        {d.winner_id === user!.id && <Crown className="h-4 w-4 text-amber-400" />}
                      </div>
                      <div className="text-xs text-ink-500">
                        Status: <span className="text-accent-300">{d.status}</span>
                      </div>
                    </div>
                    <ChevronRight className="h-4 w-4 text-ink-400" />
                  </button>
                ))}
              </div>
            )}

            {openDuels.length === 0 && myDuels.length === 0 && (
              <div className="text-sm text-ink-400 text-center py-4">
                No duels yet. Be the first to open a challenge!
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

src/components/QEDJournalExport.tsx:
import { useState } from 'react';
import { FileDown, Loader2, Award } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { useAuth } from '../lib/AuthContext';

interface Props {
  onExport?: () => void;
}

export default function QEDJournalExport({ onExport }: Props) {
  const { user } = useAuth();
  const [exporting, setExporting] = useState(false);
  const [format, setFormat] = useState<'markdown' | 'html'>('markdown');

  const exportJournal = async () => {
    if (!user) return;
    setExporting(true);

    const { data: solutions } = await supabase
      .from('solutions')
      .select(`
        id,
        body,
        created_at,
        is_correct,
        problem_id,
        problems:problem_id(title, statement, difficulty)
      `)
      .eq('author_id', user.id)
      .eq('is_correct', true)
      .order('created_at', { ascending: true });

    if (!solutions || solutions.length === 0) {
      alert('No correct solutions to export.');
      setExporting(false);
      return;
    }

    const displayName = (user.user_metadata as { display_name?: string })?.display_name || user.email?.split('@')[0] || 'Mathlete';

    if (format === 'markdown') {
      const markdown = generateMarkdown(solutions, displayName);
      downloadFile(markdown, 'qed-journal.md', 'text/markdown');
    } else {
      const html = generateHTML(solutions, displayName);
      downloadFile(html, 'qed-journal.html', 'text/html');
    }

    setExporting(false);
    onExport?.();
  };

  const generateMarkdown = (solutions: any[], name: string): string => {
    const lines: string[] = [
      `# Q.E.D. Journal`,
      `## ${name}'s Verified Solutions`,
      ``,
      `*Exported on ${new Date().toLocaleDateString()}*`,
      ``,
      `---`,
      ``,
    ];

    solutions.forEach((s, i) => {
      const problem = s.problems as any;
      lines.push(`### Problem ${i + 1}: ${problem?.title || s.problem_id}`);
      lines.push(`**Difficulty:** ${problem?.difficulty || 'Unknown'}`);
      lines.push(`**Date Solved:** ${new Date(s.created_at).toLocaleDateString()}`);
      lines.push(``);
      if (problem?.statement) {
        lines.push(`**Statement:**`);
        lines.push(problem.statement);
        lines.push(``);
      }
      lines.push(`**My Solution:**`);
      lines.push(s.body);
      lines.push(``);
      lines.push(`---`);
      lines.push(``);
    });

    lines.push(`*Total: ${solutions.length} verified solutions*`);

    return lines.join('\n');
  };

  const generateHTML = (solutions: any[], name: string): string => {
    const solutionItems = solutions.map((s, i) => {
      const problem = s.problems as any;
      return `
        <article class="solution" style="margin-bottom: 2rem; page-break-inside: avoid;">
          <h3 style="font-size: 1.25rem; margin-bottom: 0.5rem;">Problem ${i + 1}: ${problem?.title || s.problem_id}</h3>
          <div style="color: #666; margin-bottom: 1rem;">
            <span class="difficulty">${problem?.difficulty || 'Unknown'}</span> ·
            <span class="date">${new Date(s.created_at).toLocaleDateString()}</span>
          </div>
          ${problem?.statement ? `
            <div style="margin-bottom: 1rem; padding: 1rem; background: #f5f5f5; border-radius: 4px;">
              <strong>Statement:</strong>
              <p style="margin-top: 0.5rem;">${problem.statement}</p>
            </div>
          ` : ''}
          <div style="line-height: 1.8;">
            ${s.body}
          </div>
        </article>
      `;
    }).join('\n');

    return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Q.E.D. Journal - ${name}</title>
  <style>
    body {
      font-family: 'Georgia', serif;
      max-width: 800px;
      margin: 0 auto;
      padding: 2rem;
      line-height: 1.6;
      color: #333;
    }
    h1 { font-size: 2rem; text-align: center; margin-bottom: 0.5rem; }
    h2 { font-size: 1.25rem; text-align: center; color: #666; font-weight: normal; margin-bottom: 2rem; }
    h3 { font-size: 1.25rem; }
    h4 { font-size: 1rem; }
    .difficulty {
      display: inline-block;
      padding: 0.25rem 0.5rem;
      background: #e0f2fe;
      color: #0369a1;
      border-radius: 4px;
      font-size: 0.75rem;
      text-transform: uppercase;
    }
    code { font-family: monospace; background: #f5f5f5; padding: 0.125rem 0.25rem; }
    pre { background: #f5f5f5; padding: 1rem; border-radius: 4px; overflow-x: auto; }
    blockquote { border-left: 3px solid #ccc; padding-left: 1rem; margin-left: 0; color: #666; }
    article { border-bottom: 1px solid #eee; padding-bottom: 1.5rem; }
    @media print {
      body { padding: 0; }
      article { page-break-inside: avoid; }
    }
  </style>
  <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/katex@0.16.9/dist/katex.min.css">
  <script defer src="https://cdn.jsdelivr.net/npm/katex@0.16.9/dist/katex.min.js"></script>
  <script defer src="https://cdn.jsdelivr.net/npm/katex@0.16.9/dist/contrib/auto-render.min.js"></script>
  <script>
    document.addEventListener("DOMContentLoaded", function() {
      renderMathInElement(document.body, {
        delimiters: [
          {left: '$$', right: '$$', display: true},
          {left: '$', right: '$', display: false}
        ]
      });
    });
  </script>
</head>
<body>
  <h1>Q.E.D. Journal</h1>
  <h2>${name}'s Verified Solutions</h2>
  <p style="text-align: center; color: #666;">Exported on ${new Date().toLocaleDateString()}</p>
  <hr style="margin: 2rem 0; border: none; border-top: 1px solid #eee;">
  ${solutionItems}
  <footer style="text-align: center; color: #999; margin-top: 2rem;">
    <p>Total: ${solutions.length} verified solutions</p>
  </footer>
</body>
</html>`;
  };

  const downloadFile = (content: string, filename: string, type: string) => {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-4 space-y-4">
      <div className="flex items-center gap-2">
        <Award className="h-5 w-5 text-amber-400" />
        <h4 className="font-serif text-lg text-ink-50">Q.E.D. Journal Export</h4>
      </div>
      <p className="text-sm text-ink-400">
        Export all your verified correct solutions as a beautiful, print-ready document.
      </p>
      <div className="flex items-center gap-3">
        <select
          value={format}
          onChange={(e) => setFormat(e.target.value as 'markdown' | 'html')}
          className="rounded-md border border-ink-700 bg-ink-900 px-2 py-1.5 text-sm text-ink-100"
        >
          <option value="markdown">Markdown (.md)</option>
          <option value="html">HTML (.html)</option>
        </select>
        <button
          onClick={exportJournal}
          disabled={exporting || !user}
          className="focus-ring flex items-center gap-1.5 rounded-md border border-accent-400 bg-accent-400/15 px-4 py-2 text-sm font-semibold text-accent-200 hover:bg-accent-400/25 disabled:opacity-50"
        >
          {exporting ? <Loader2 className="h-4 w-4 animate-spin" /> : <FileDown className="h-4 w-4" />}
          Export my Journal
        </button>
      </div>
    </div>
  );
}

src/components/SkillTree.tsx:
import { useEffect, useState } from 'react';
import { supabase } from '../lib/supabaseClient';
import { useAuth } from '../lib/AuthContext';

export interface SkillNode {
  id: string;
  title: string;
  description: string | null;
  subject: string;
  difficulty: string;
  order_index: number;
  required_xp: number;
  problem_ids: string[];
  completed?: boolean;
  prerequisites?: string[];
}

interface Props {
  onSelectNode?: (node: SkillNode) => void;
}

const SUBJECT_COLORS: Record<string, { bg: string; border: string; text: string }> = {
  algebra: { bg: 'bg-violet-500/20', border: 'border-violet-500/40', text: 'text-violet-300' },
  number_theory: { bg: 'bg-amber-500/20', border: 'border-amber-500/40', text: 'text-amber-300' },
  combinatorics: { bg: 'bg-emerald-500/20', border: 'border-emerald-500/40', text: 'text-emerald-300' },
  geometry: { bg: 'bg-sky-500/20', border: 'border-sky-500/40', text: 'text-sky-300' },
  analysis: { bg: 'bg-rose-500/20', border: 'border-rose-500/40', text: 'text-rose-300' },
  general: { bg: 'bg-ink-500/20', border: 'border-ink-500/40', text: 'text-ink-300' },
};

const SUBJECT_ORDER = ['general', 'algebra', 'number_theory', 'combinatorics', 'geometry', 'analysis'];

export default function SkillTree({ onSelectNode }: Props) {
  const { user, configured } = useAuth();
  const [nodes, setNodes] = useState<SkillNode[]>([]);
  const [prereqs, setPrereqs] = useState<Record<string, string[]>>({});
  const [progress, setProgress] = useState<Record<string, boolean>>({});
  const [loading, setLoading] = useState(true);
  const [selectedSubject, setSelectedSubject] = useState<string>('all');

  useEffect(() => {
    if (!configured) {
      setLoading(false);
      return;
    }
    loadData();
  }, [user, configured]);

  const loadData = async () => {
    setLoading(true);
    const { data: nodesData } = await supabase
      .from('skill_nodes')
      .select('*')
      .order('order_index', { ascending: true });

    const { data: prereqsData } = await supabase
      .from('skill_node_prerequisites')
      .select('node_id, prerequisite_id');

    const prereqMap: Record<string, string[]> = {};
    (prereqsData || []).forEach((p: { node_id: string; prerequisite_id: string }) => {
      if (!prereqMap[p.node_id]) prereqMap[p.node_id] = [];
      prereqMap[p.node_id].push(p.prerequisite_id);
    });
    setPrereqs(prereqMap);

    if (user) {
      const { data: progressData } = await supabase
        .from('user_skill_progress')
        .select('node_id, completed')
        .eq('user_id', user.id);

      const progressMap: Record<string, boolean> = {};
      (progressData || []).forEach((p: { node_id: string; completed: boolean }) => {
        progressMap[p.node_id] = p.completed;
      });
      setProgress(progressMap);
    }

    if (nodesData) {
      setNodes(nodesData as SkillNode[]);
    }
    setLoading(false);
  };

  const isNodeUnlocked = (node: SkillNode): boolean => {
    const nodePrereqs = prereqs[node.id] || [];
    if (nodePrereqs.length === 0) return true;
    return nodePrereqs.every((pid) => progress[pid]);
  };

  const filteredNodes = selectedSubject === 'all'
    ? nodes
    : nodes.filter((n) => n.subject === selectedSubject);

  const grouped = SUBJECT_ORDER.reduce((acc, subject) => {
    const subjectNodes = filteredNodes.filter((n) => n.subject === subject);
    if (subjectNodes.length > 0) acc[subject] = subjectNodes;
    return acc;
  }, {} as Record<string, SkillNode[]>);

  if (loading) {
    return <div className="text-sm text-ink-400">Loading skill tree...</div>;
  }

  if (nodes.length === 0) {
    return (
      <div className="rounded-lg border border-ink-700 bg-ink-850/50 p-6 text-center">
        <p className="text-sm text-ink-400">
          The skill tree is being set up. Check back soon!
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap items-center gap-2">
        <button
          onClick={() => setSelectedSubject('all')}
          className={`px-3 py-1.5 rounded-md text-xs font-medium transition ${
            selectedSubject === 'all'
              ? 'bg-accent-400/20 text-accent-200 border border-accent-400/40'
              : 'bg-ink-800 text-ink-400 hover:text-ink-200'
          }`}
        >
          All
        </button>
        {SUBJECT_ORDER.filter((s) => grouped[s]?.length > 0).map((subject) => {
          const colors = SUBJECT_COLORS[subject];
          return (
            <button
              key={subject}
              onClick={() => setSelectedSubject(subject)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition ${
                selectedSubject === subject
                  ? `${colors.bg} ${colors.text} border ${colors.border}`
                  : 'bg-ink-800 text-ink-400 hover:text-ink-200'
              }`}
            >
              {subject.replace('_', ' ').replace(/\b\w/g, (c) => c.toUpperCase())}
            </button>
          );
        })}
      </div>

      {Object.entries(grouped).map(([subject, subjectNodes]) => (
        <div key={subject} className="space-y-3">
          <h3 className={`text-sm font-medium ${SUBJECT_COLORS[subject]?.text || 'text-ink-300'}`}>
            {subject.replace('_', ' ').replace(/\b\w/g, (c) => c.toUpperCase())}
          </h3>
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
            {subjectNodes.map((node) => {
              const unlocked = isNodeUnlocked(node);
              const completed = progress[node.id];
              const colors = SUBJECT_COLORS[node.subject];

              return (
                <button
                  key={node.id}
                  onClick={() => onSelectNode?.(node)}
                  disabled={!unlocked}
                  className={`relative rounded-lg border p-4 text-left transition ${
                    completed
                      ? `${colors.bg} ${colors.border}`
                      : unlocked
                        ? 'bg-ink-850/50 border-ink-700 hover:border-ink-600'
                        : 'bg-ink-900/30 border-ink-800 opacity-50 cursor-not-allowed'
                  }`}
                >
                  <div className="flex items-start gap-3">
                    <div className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full border ${
                      completed
                        ? `${colors.border} ${colors.bg}`
                        : unlocked
                          ? 'border-ink-600 bg-ink-800'
                          : 'border-ink-700 bg-ink-900'
                    }`}>
                      <span className={`text-xs font-mono ${completed ? colors.text : 'text-ink-400'}`}>
                        {node.order_index}
                      </span>
                    </div>
                    <div>
                      <h4 className={`text-sm font-medium ${completed ? colors.text : unlocked ? 'text-ink-100' : 'text-ink-500'}`}>
                        {node.title}
                      </h4>
                      <p className="mt-1 text-xs text-ink-500 line-clamp-2">
                        {node.description || node.difficulty}
                      </p>
                    </div>
                  </div>
                  {completed && (
                    <div className="absolute right-2 top-2 text-accent-400">
                      <svg className="h-4 w-4" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                      </svg>
                    </div>
                  )}
                  {!unlocked && (
                    <div className="absolute right-2 top-2 text-ink-500">
                      <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                      </svg>
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}

