src/index.css:
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  color-scheme: dark;
}

html,
body,
#root {
  height: 100%;
}

body {
  background-color: #0b0f19;
  color: #e6e9f2;
  font-family: 'Inter', ui-sans-serif, system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

/* Subtle grid backdrop */
.bg-grid {
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.025) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.025) 1px, transparent 1px);
  background-size: 48px 48px;
  background-position: -1px -1px;
}

.bg-radial-accent {
  background:
    radial-gradient(60% 50% at 50% 0%, rgba(34, 224, 200, 0.08) 0%, transparent 70%),
    radial-gradient(40% 30% at 100% 0%, rgba(120, 180, 255, 0.05) 0%, transparent 70%);
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}
::-webkit-scrollbar-track {
  background: #0b0f19;
}
::-webkit-scrollbar-thumb {
  background: #1c2438;
  border-radius: 6px;
  border: 2px solid #0b0f19;
}
::-webkit-scrollbar-thumb:hover {
  background: #2a3450;
}

/* KaTeX tweaks */
.katex {
  font-size: 1.05em;
}
.katex-display {
  margin: 1.4em 0;
  overflow-x: auto;
  overflow-y: hidden;
  padding: 2px 0;
}
.katex-display > .katex {
  white-space: normal;
}

/* Markdown body */
.prose-math {
  color: #c2c9de;
  line-height: 1.7;
}
.prose-math h1,
.prose-math h2,
.prose-math h3 {
  color: #e6e9f2;
  font-weight: 600;
  line-height: 1.25;
  margin-top: 1.6em;
  margin-bottom: 0.6em;
}
.prose-math h1 { font-size: 1.5rem; }
.prose-math h2 { font-size: 1.25rem; }
.prose-math h3 { font-size: 1.1rem; }
.prose-math p {
  margin: 0.8em 0;
}
.prose-math ul,
.prose-math ol {
  margin: 0.8em 0;
  padding-left: 1.4em;
}
.prose-math ul { list-style: disc; }
.prose-math ol { list-style: decimal; }
.prose-math li { margin: 0.25em 0; }
.prose-math code {
  font-family: 'JetBrains Mono', monospace;
  background: rgba(255, 255, 255, 0.06);
