  return (
    <div className="rounded-xl border border-ink-700 bg-ink-850/50 p-5">
      <div className={`mb-2 flex h-9 w-9 items-center justify-center rounded-md border border-ink-700 bg-ink-900 ${accent}`}>
        {icon}
