              <h1 className="max-w-3xl font-serif text-4xl font-semibold leading-tight text-ink-50 sm:text-5xl">
                {week.title}
              </h1>
              <p className="max-w-2xl text-base text-ink-300 sm:text-lg">{week.description}</p>
