CREATE POLICY "update_own_duel" ON proof_duels FOR UPDATE
  TO authenticated USING (auth.uid() = challenger_id OR auth.uid() = defender_id);

-- 2. SKILL NODES ----------------------------------------------------
CREATE TABLE IF NOT EXISTS skill_nodes (
